//Import required packages/dependencies
const express = require('express');  //Web framework to handle requests-responses easier than you do it manually on HTTP methods (GET, POST etc) and allow us use middleware functions we need in our server. A lot of functionality can be accessed from the native NodeJS module which simplifies tasks for all developers
const bodyParser = require('body-parser');  //Middle ware to handle raw data JSON like requests into a format you have control over - easy way, not just middleware that parses json but also includes it in req.body object when using POST request (for reading payloads)   A common misconception is the body parser only works with HTML forms and doesn't work directly on streamed bodies like SMS messages due to which Twilio requires a multipart/form-data format
const twilio = require('twilio');  //JavaScript SDK for accessing our application using Twillios APIs. This way we don’t need access tokens or anything else from within NodeJS, and the code will look cleaner as well because everything is encapsulated in one place that doesn's know about all internal components of Twitter
const crypto = require('crypto'); //To generate random codes for two factor authentication 
  
//Initialize Express App. We create an express application to get up and running with Node & dependencies we need on starting the app: body parser which handles HTTP POST requests into usable JSON, Twilio client that will handle our SMS functionality from twillios APIs server settings (TwiML) where it would send a response back
const app = express();  
app.use(bodyParser.json());  //We use Express's middleware to help parse the request body which can be in JSON format, Twilio will read this data and pass on into req/res objects via callback function so we need these packages installed (Express + Body Parser) for that
app.use(twilio(process.env.TWILIO_ACCOUNT_SID, process.env.TWILIO_AUTH_TOKEN)); //Setting up Twillios SDK - get hold of your account SID and Auth token from the twilioconfig
  
//Create route handler for POST request to /sms/send which will send a user code as response back via sms (using two-factor authentication)  when calling URL "/your_url" on browser. To receive this call at server side use an Express middleware, e.g., app.post('/verify', twilio.requestMiddleware(function(req, res))
app.post("/send", (req, res) => { //Setting up a post request route /sms/Send and respond with json containing two factor authentication code sent via sms using Twillios service  by generating random codes in server side for each user session - this is the function which gets triggered on clicking button within client-side app
    const recipient = req.body['phone_number']; //Extracting phone number from request body to send SMS message with that particular numbers's mobile device as recipients(the one used by users)  in Twilio sms service for two step verification   and the function gets trigger when user inputs code entered on client side
    const authCode = crypto.randomInt(100000,999999); //Creating random number (code - one-time password) to be sent via SMS as 2FA token in server app where the incoming POST request body's code is compared with this
    console.log("Auth Code", authCode );  
       twilio.messages.create({                                  //Sending message using Twillios API sending a text-message to phone_number sent via SMS from our client  server app for validation, and the function gets triggered when user enters code received on mobile device in browser (client side) with URL '/your_url'
          body: `Your verification Code is ${authCode}` , //Text message containing confirmation of two factor authentication - a single-use password sent via SMS to client app for validation,  which Twilio API can compare the request code against.     and gets triggered when user enters this random number (code) in browser as POST data at '/your_url' URL
          to: recipient ,   //Phone numbers that received a text message are listed here - you could also use their cellphone for enhanced security, which Twilio would send the SMS through if they have phone-based setup.  In real world scenario user has two factor authentication so we just need one more input (code) from them
          from: process.env.TWILIO_PHONE_NUMBER //The number you bought our message to, e.g., the Twilio Phone Number - can be your personal phone like '+1502346789' or a standard carrier-provided Voice Calling Service such as what’s called SIM Card Services
      })   .then((message) => { //This promise gets triggered when message successfully sent, the response back to client app  and user will receive confirmation of successful sms textual messages. Twilio REST API v2 sends a HTTP POST request containing details on what just happened in this case i am providing json with body - {'phone_number': '+150xx4xxxx'}
          console.log(`Message sent: ${message.sid}! Message status:${message.status}, message body : {msg}:  Twilio API responded as follows- responseBody is:- `, JSON.stringify({success: true})) //Printing confirmation for the server and user
          res.json(JSON.parse('{"phone_number":"' + req.body['phone_number']+'","authCode":"}'  + authCode))  ;//Sending back data with phone number to client app in response body format, so that this request could be identified as verification process for user and on success - server responds successfully
      }) // If the message fails we handle it here. For a real scenario you should check Twilio REST API error documentation (https://www.twilio.com/docs/verify/errors) to see all errors that might occur during process of sending SMS  messages and handling responses in Express server
});   //end route handler for post request - '/sms/send' with body containing phone_number received from client app URL /your url on browser where user enters the sent code as POST data at this endpoint (in our express application) to validate verification process. For real world use-case, you should handle multiple scenarios and errors in your server
  
//Setting up port for Express Application by specifying a specific HTTP protocol(http), hostname or IP address on which we'll expose the app (->3001). In this case - our local machine. Also using NodeJS built-in 'app'.listen method to tell node is going ahead and listening at provided ports
const PORT = process.env.PORT || 5298;   //This sets port in which express web server will listen when starting from a production environment, or 3047 if none exist - making sure it’s not used by other applications running on default OS assigned localhost:Port Number (Default to http://localhost)
app.listen(PORT , () => console.log('server is listening at port ', PORT)); //Setting up server connection with the specified endpoint in browser or IDE, so express app can respond according  user's request for both client side and also on backend - a unique identifier of each time when we start our NodeJS application